import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import { copySudokuBoard, createSudokuBoard } from '@algorithm.ts/sudoku'
import { GameRunningStatus } from '@kyokuya/react-game-core'
import type { ISudokuInstruction } from '../instruction/types'
import { runInstructs } from '../instruction/util'
import type { ISudokuBoardCell } from '../types'
import { getSudokuCreator } from '../util/creator'
import { checkCompleted, checkPlaying } from '../util/status'

export interface ISudokuState {
  /**
   * Sudoku size, sqrt of the number of rows or columns.
   */
  SUDOKU_SIZE_SQRT: 2 | 3 | 4
  /**
   * Game difficulty.
   */
  difficulty: number
  /**
   * Displayed radix.
   */
  radix: 10 | 16
  /**
   * Game status.
   */
  gameStatus: GameRunningStatus
  /**
   * Total score.
   */
  score: number
  /**
   * Sudoku puzzle.
   */
  puzzle: Readonly<ISudokuBoard>
  /**
   * Solution of the puzzle.
   */
  solution: Readonly<ISudokuBoard>
  /**
   * Attempt on the puzzle.
   */
  attemptRef: {
    current: Readonly<ISudokuBoard>
  }
  /**
   * Player instructions.
   */
  instructions: ReadonlyArray<ISudokuInstruction>
  /**
   * Currently activated board cell.
   */
  activatedCell: Readonly<ISudokuBoardCell>
  /**
   * The coordinate of the board cell for hint.
   */
  hintCell: Readonly<ISudokuBoardCell> | null
  /**
   * Whether to display the solution of the quiz.
   */
  cheatVisible: boolean
  /**
   * Time spent in this game
   */
  usedTimeRef: {
    current: number
  }
  /**
   * Used to judge if the game has restarted.
   */
  gameTick: number
  /**
   * Times of attempt on the current game.
   */
  attemptTick: number
  /**
   * To retrigger the hint animation when the multiple times hint requests on a
   * same cell were fired.
   */
  hintTick: number
}

export const initSudokuState = (initialState?: Partial<ISudokuState>): ISudokuState => {
  const {
    SUDOKU_SIZE_SQRT = 3,
    difficulty = 20,
    score = 0,
    radix = 10,
    activatedCell,
    gameTick = 0,
    puzzle: _puzzle,
    solution: _solution,
    instructions = [],
    usedTimeRef = { current: 0 },
  } = { ...initialState }

  const SUDOKU_SIZE = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT
  const { puzzle, solution } =
    _puzzle && _solution
      ? { puzzle: _puzzle!, solution: _solution! }
      : getSudokuCreator(SUDOKU_SIZE_SQRT).createSudoku(difficulty / 100)

  const attempt = createSudokuBoard(SUDOKU_SIZE)
  copySudokuBoard(puzzle, attempt as ISudokuBoard)
  runInstructs(attempt, instructions)

  const { r = -1, c = -1 } = activatedCell ?? {}
  const gameStatus: GameRunningStatus = checkCompleted(SUDOKU_SIZE, attempt, solution)
    ? GameRunningStatus.FINISHED
    : checkPlaying(SUDOKU_SIZE, attempt, puzzle)
    ? GameRunningStatus.PAUSED
    : GameRunningStatus.PENDING

  return {
    SUDOKU_SIZE_SQRT,
    difficulty,
    radix,
    gameStatus,
    score,
    attemptRef: { current: attempt },
    instructions,
    puzzle,
    solution,
    activatedCell: { r, c },
    hintCell: null,
    cheatVisible: false,
    usedTimeRef,
    gameTick,
    attemptTick: 0,
    hintTick: 0,
  }
}
