import { GameRunningStatus } from '@kyokuya/react-game-core'
import { SudokuActionType, SudokuContextType } from '@kyokuya/react-game-sudoku-core'
import type { SelectChangeEvent } from '@mui/material'
import { MenuItem, Select, Slider } from '@mui/material'
import React from 'react'

export const GameSettings: React.FC = () => {
  const { state, dispatch } = React.useContext(SudokuContextType)
  const { SUDOKU_SIZE_SQRT, difficulty, radix, gameStatus } = state
  const isPending: boolean = gameStatus === GameRunningStatus.PENDING

  const actions = React.useMemo(
    () => ({
      onSizeChange: (e: SelectChangeEvent<number>): void => {
        dispatch({
          type: SudokuActionType.RESET,
          payload: { SUDOKU_SIZE_SQRT: Number(e.target.value) as 2 | 3 | 4 },
        })
      },
      onRadixChange: (e: SelectChangeEvent<number>): void => {
        dispatch({
          type: SudokuActionType.RESET,
          payload: { radix: Number(e.target.value) as 10 | 16 },
        })
      },
      onDifficultyChange: (_e: Event, v: number | number[]): void => {
        dispatch({
          type: SudokuActionType.RESET,
          payload: { difficulty: v as number },
        })
      },
    }),
    [dispatch],
  )

  return (
    <div className="kyokuya-sudoku__game-settings">
      <div className="kyokuya-sudoku__game-settings-item">
        <span>Size:</span>
        <Select
          variant="standard"
          value={SUDOKU_SIZE_SQRT}
          disabled={!isPending}
          onChange={actions.onSizeChange}
        >
          <MenuItem value={2}>4x4</MenuItem>
          <MenuItem value={3}>9x9</MenuItem>
          <MenuItem value={4}>16x16</MenuItem>
        </Select>
      </div>
      <div className="kyokuya-sudoku__game-settings-item">
        <span>Radix:</span>
        <Select
          variant="standard"
          value={radix}
          disabled={!isPending}
          onChange={actions.onRadixChange}
        >
          <MenuItem value={10}>Decimal (x10)</MenuItem>
          <MenuItem value={16}>Hexadecimal (x16)</MenuItem>
        </Select>
      </div>
      <div className="kyokuya-sudoku__game-settings-item kyokuya-sudoku__game-settings-item-difficulty">
        <span>Difficulty:</span>
        <Slider
          value={difficulty}
          disabled={!isPending}
          step={1}
          min={0}
          max={100}
          valueLabelDisplay="auto"
          aria-labelledby="sudoku-difficulty"
          onChange={actions.onDifficultyChange}
        />
      </div>
    </div>
  )
}

GameSettings.displayName = 'SudokuGameSettings'
