import type { ISudokuBoard } from '@algorithm.ts/sudoku'
import { createSegmentCodeMap } from '@algorithm.ts/sudoku'
import type { ISudokuBoardCell } from '@kyokuya/react-game-sudoku-core'
import {
  SudokuActionType,
  SudokuContextType,
  generateDuplicatedMap,
} from '@kyokuya/react-game-sudoku-core'
import cn from 'clsx'
import PropTypes from 'prop-types'
import React from 'react'
import SudokuBoardBorders from './SudokuBoardBorders'

export interface ISudokuBoardProps {
  /**
   * An attempt at a puzzle.
   */
  attempt: Readonly<ISudokuBoard>
  /**
   * The coordinate of the board cell for hint.
   */
  hintCell: ISudokuBoardCell | null
  /**
   * CSS class name.
   */
  className?: string
  /**
   * Sudoku board overlay.
   */
  overlay?: React.ReactNode
  /**
   * Callback function triggered when a grid is clicked.
   */
  onCellClick?(r: number, c: number): void
}

/**
 * Render a sudoku board.
 *
 * @param props
 * @returns
 */
export const SudokuBoard: React.FC<ISudokuBoardProps> = props => {
  const { attempt, hintCell, className, overlay, onCellClick } = props
  const { state, dispatch } = React.useContext(SudokuContextType)
  const { SUDOKU_SIZE_SQRT, radix, puzzle, solution, activatedCell, hintTick } = state
  const SUDOKU_SIZE: number = SUDOKU_SIZE_SQRT * SUDOKU_SIZE_SQRT

  const handleCellClick = React.useCallback(
    (r: number, c: number) => {
      if (onCellClick != null) onCellClick(r, c)
      dispatch({
        type: SudokuActionType.ACTIVE,
        payload: { r, c },
      })
    },
    [dispatch, onCellClick],
  )

  const segmentNoMap = createSegmentCodeMap(SUDOKU_SIZE_SQRT)
  const duplicatedMap = generateDuplicatedMap(SUDOKU_SIZE_SQRT, attempt)

  const { r: R, c: C } = activatedCell
  const V = R === -1 ? -1 : attempt[R][C]

  const { r: hr = -1, c: hc = -1 } = hintCell ?? {}
  const hv = hr === -1 || hc === -1 ? -1 : solution[hr][hc]

  const R0 = R === -1 ? -1 : segmentNoMap[R]
  const C0 = C === -1 ? -1 : segmentNoMap[C]

  const cells: React.ReactNode[] = []
  for (let r = 0, idx = 0; r < SUDOKU_SIZE; ++r) {
    const row: React.ReactNode[] = []
    for (let c = 0; c < SUDOKU_SIZE; ++c, ++idx) {
      const v: number = attempt[r][c]
      const isHint: boolean = r === hr && c === hc
      const isActivated: boolean = r === R && c === C
      const isRelate: boolean =
        !isActivated && (r === R || c === C || (segmentNoMap[r] === R0 && segmentNoMap[c] === C0))
      const isSame: boolean = V === -1 ? false : v === V && !isRelate && !isActivated
      const isDuplicated = !!duplicatedMap[idx]

      const value = isHint ? hv : v
      const cell = (
        <span
          key={isHint ? `${c}-hint-${hintTick}` : c}
          className={cn('kyokuya-sudoku__board-cell', {
            'kyokuya-sudoku__board-cell--left-seamless': c === 0,
            'kyokuya-sudoku__board-cell--left': c > 0 && c % SUDOKU_SIZE_SQRT === 0,
            'kyokuya-sudoku__board-cell--top-seamless': r === 0,
            'kyokuya-sudoku__board-cell--top': r > 0 && r % SUDOKU_SIZE_SQRT === 0,
            'kyokuya-sudoku__board-cell--preset': v !== -1,
            'kyokuya-sudoku__board-cell--attempt': v !== puzzle[r][c],
            'kyokuya-sudoku__board-cell--duplicated': isDuplicated,
            'kyokuya-sudoku__board-cell--hint': isHint,
            'kyokuya-sudoku__board-cell--activated': isActivated,
            'kyokuya-sudoku__board-cell--related': isRelate,
            'kyokuya-sudoku__board-cell--same': isSame,
          })}
        >
          <span
            className="kyokuya-sudoku__board-cell-content"
            onClick={() => handleCellClick(r, c)}
          >
            {value === -1 ? '' : (value + 1).toString(radix)}
          </span>
        </span>
      )
      row.push(cell)
    }
    cells.push(
      <div key={r} className="kyokuya-sudoku__board-row">
        {row}
      </div>,
    )
  }

  return (
    <div className={cn('kyokuya-sudoku__board', className)}>
      <div key="overlay" className="kyokuya-sudoku__board-overlay">
        {overlay}
      </div>
      <SudokuBoardBorders SUDOKU_SIZE_SQRT={SUDOKU_SIZE_SQRT} />
      <div key="wrapper" className="kyokuya-sudoku__board-wrapper">
        {cells}
      </div>
    </div>
  )
}

SudokuBoard.propTypes = {
  attempt: PropTypes.array.isRequired,
  className: PropTypes.string,
  overlay: PropTypes.node,
  onCellClick: PropTypes.func,
}

SudokuBoard.displayName = 'SudokuBoard'
export default SudokuBoard
