export enum SudokuInstructionType {
  ERASE = 'erase',
  HINT = 'hint',
  WRITE = 'write',
}

export type ISudokuInstruction =
  | {
      type: SudokuInstructionType.ERASE
      payload: { r: number; c: number }
      timestamp: string // ISO string
    }
  | {
      type: SudokuInstructionType.HINT
      payload: { r: number; c: number }
      timestamp: string // ISO string
    }
  | {
      type: SudokuInstructionType.WRITE
      payload: { r: number; c: number; v: number }
      timestamp: string // ISO string
    }
