import type { ISudokuBoard } from '@algorithm.ts/sudoku'

/**
 * Check if the puzzle solved.
 * @param SUDOKU_SIZE
 * @param attempt
 * @param solution
 * @returns
 */
export const checkCompleted = (
  SUDOKU_SIZE: number,
  attempt: Readonly<ISudokuBoard>,
  solution: Readonly<ISudokuBoard>,
): boolean => {
  return isEqualBoard(SUDOKU_SIZE, attempt, solution)
}

/**
 * Check if the game has started
 * @param SUDOKU_SIZE
 * @param attempt
 * @param solution
 * @returns
 */
export const checkPlaying = (
  SUDOKU_SIZE: number,
  attempt: Readonly<ISudokuBoard>,
  puzzle: Readonly<ISudokuBoard>,
): boolean => {
  return !isEqualBoard(SUDOKU_SIZE, attempt, puzzle)
}

export const isEqualBoard = (
  SUDOKU_SIZE: number,
  board1: Readonly<ISudokuBoard>,
  board2: Readonly<ISudokuBoard>,
): boolean => {
  for (let r = 0; r < SUDOKU_SIZE; ++r) {
    for (let c = 0; c < SUDOKU_SIZE; ++c) {
      if (board1[r][c] !== board2[r][c]) return false
    }
  }
  return true
}
